mapper.select:
SELECT U.USER_ID AS "userId", U.USER_NAME AS "userName", U.BRANCH_ID AS "branchId", U.AUTH_GROUP_ID AS "authGroupId", G.AUTH_GROUP_NAME AS "authGroupName", U.USE_YN AS "useYn", U.LAST_LOGIN_TIME AS "lastLoginTime" FROM OM_USER U LEFT JOIN OM_AUTH_GROUP G ON U.AUTH_GROUP_ID = G.AUTH_GROUP_ID WHERE 1 = 1
AND U.USER_ID LIKE '%' || #{userId} || '%'
AND U.USER_NAME LIKE '%' || #{userName} || '%'
AND U.BRANCH_ID = #{branchId}
AND U.AUTH_GROUP_ID = #{authGroupId}
AND U.USE_YN = #{useYn}
ORDER BY U.USER_ID
OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
  FROM OM_USER U
 WHERE 1 = 1

    AND U.USER_ID LIKE '%' || #{userId} || '%'


    AND U.USER_NAME LIKE '%' || #{userName} || '%'


    AND U.BRANCH_ID = #{branchId}


    AND U.AUTH_GROUP_ID = #{authGroupId}


    AND U.USE_YN = #{useYn}

mapper.update:
UPDATE OM_USER
   SET USER_NAME = #{userName},
       BRANCH_ID = #{branchId},
       AUTH_GROUP_ID = #{authGroupId},
       USE_YN = #{useYn}
 WHERE USER_ID = #{userId}

UPDATE OM_USER
   SET LAST_LOGIN_TIME = #{lastLoginTime}
 WHERE USER_ID = #{userId}

UPDATE OM_USER
   SET PASSWORD_HASH = #{passwordHash}
 WHERE USER_ID = #{userId}

mapper.select:
SELECT MENU_ID AS "menuId", MENU_NAME AS "menuName", MENU_URL AS "menuUrl", PARENT_MENU_ID AS "parentMenuId", SORT_ORDER AS "sortOrder", USE_YN AS "useYn" FROM OM_MENU WHERE 1 = 1
AND USE_YN = #{useYn}
ORDER BY SORT_ORDER, MENU_ID

SELECT AUTH_GROUP_ID AS "authGroupId", AUTH_GROUP_NAME AS "authGroupName", DESCRIPTION AS "description", USE_YN AS "useYn" FROM OM_AUTH_GROUP WHERE 1 = 1
AND AUTH_GROUP_ID = #{authGroupId}
ORDER BY AUTH_GROUP_ID

SELECT ERROR_CODE AS "errorCode", ERROR_CATEGORY AS "errorCategory", USER_MESSAGE AS "userMessage", OPERATOR_MESSAGE AS "operatorMessage", ACTION_GUIDE AS "actionGuide", NOTIFY_TARGET AS "notifyTarget", USE_YN AS "useYn" FROM OM_ERROR_CODE WHERE 1 = 1
AND ERROR_CODE LIKE '%' || #{errorCode} || '%'
AND ERROR_CATEGORY = #{errorCategory}
AND USE_YN = #{useYn}
ORDER BY ERROR_CODE
OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
  FROM OM_ERROR_CODE
 WHERE 1 = 1

    AND ERROR_CODE LIKE '%' || #{errorCode} || '%'


    AND ERROR_CATEGORY = #{errorCategory}


    AND USE_YN = #{useYn}

SELECT JOB_ID AS "jobId", JOB_NAME AS "jobName", BUSINESS_CODE AS "businessCode", CRON_EXPR AS "cronExpr", USE_YN AS "useYn", DESCRIPTION AS "description" FROM OM_BATCH_JOB WHERE 1 = 1
AND BUSINESS_CODE = #{businessCode}
AND USE_YN = #{useYn}
ORDER BY JOB_ID

SELECT CONFIG_KEY AS "configKey", CONFIG_CATEGORY AS "configCategory", CONFIG_VALUE AS "configValue", EDITABLE_YN AS "editableYn", DESCRIPTION AS "description" FROM OM_SYSTEM_CONFIG WHERE 1 = 1
AND CONFIG_CATEGORY = #{configCategory}
ORDER BY CONFIG_CATEGORY, CONFIG_KEY

SELECT CODE_GROUP AS "codeGroup", CODE AS "code", CODE_NAME AS "codeName",
       SORT_ORDER AS "sortOrder", USE_YN AS "useYn", DESCRIPTION AS "description",
       CREATED_AT AS "createdAt", UPDATED_AT AS "updatedAt"
  FROM OM_COMMON_CODE
 WHERE CODE_GROUP = #{codeGroup}
   AND CODE = #{code}

mapper.insert:
INSERT INTO OM_COMMON_CODE (
    CODE_GROUP, CODE, CODE_NAME, SORT_ORDER, USE_YN, DESCRIPTION, CREATED_AT, UPDATED_AT
) VALUES (
    #{codeGroup}, #{code}, #{codeName}, #{sortOrder}, #{useYn}, #{description},
    #{createdAt}, #{updatedAt}
)

mapper.update:
