   SET CODE_NAME = #{codeName},
       SORT_ORDER = #{sortOrder},
       USE_YN = #{useYn},
       DESCRIPTION = #{description},
       UPDATED_AT = #{updatedAt}
 WHERE CODE_GROUP = #{codeGroup}
   AND CODE = #{code}

UPDATE OM_COMMON_CODE
   SET USE_YN = 'N',
       UPDATED_AT = #{updatedAt}
 WHERE CODE_GROUP = #{codeGroup}
   AND CODE = #{code}

